    63→func (v *authorizingVisitor) visit(source fmt.Stringer, rule *rbacv1.PolicyRule, err error) bool {
    64→	if rule != nil && RuleAllows(v.requestAttributes, rule) {
    65→		v.allowed = true
    66→		v.reason = fmt.Sprintf("RBAC: allowed by %s", source.String())
