   168→// Rule returns PolicyRule and error.
   169→func (r *PolicyRuleBuilder) Rule() (PolicyRule, error) {
   170→	if len(r.PolicyRule.Verbs) == 0 {
   171→		return PolicyRule{}, fmt.Errorf("verbs are required: %#v", r.PolicyRule)
