   173→
   174→	switch {
   175→	case len(r.PolicyRule.NonResourceURLs) > 0:
   176→		if len(r.PolicyRule.APIGroups) != 0 || len(r.PolicyRule.Resources) != 0 || len(r.PolicyRule.ResourceNames) != 0 {
